#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long a; bool sorted=true; long long prev=0;
        long long *arr = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++){
            scanf("%lld",&a);
            arr[i]=a;
            if(i>0 && arr[i-1]>arr[i]) sorted=false;
        }
        char s[200005]; scanf("%s",s);
        if(sorted){
            printf("0\n");
            free(arr);
            continue;
        }
        bool hasN=false, hasS=false;
        for(int i=0;i<N;i++){
            if(s[i]=='N') hasN=true; else hasS=true;
        }
        if(!(hasN && hasS)){
            printf("-1\n");
        }else if(s[0]!=s[N-1]){
            printf("1\n");
        }else{
            printf("2\n");
        }
        free(arr);
    }
    return 0;
}

