        }
        string pol; cin>>pol;
        if(sorted){
            cout<<0<<"\n";
            continue;
        }
        bool hasN=false, hasS=false;
        for(char c:pol){ if(c=='N') hasN=true; else hasS=true; }
        if(!(hasN && hasS)) cout<<-1<<"\n";
        else if(pol.front()!=pol.back()) cout<<1<<"\n";
        else cout<<2<<"\n";
    }
    return 0;
}

