import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[] a = new long[N];
            StringTokenizer st = new StringTokenizer(br.readLine());
            boolean sorted = true;
            for (int i = 0; i < N; i++) {
                a[i] = Long.parseLong(st.nextToken());
                if (i > 0 && a[i-1] > a[i]) sorted = false;
            }
            String pol = br.readLine().trim();
            if (sorted) {
                out.append(0).append('\n');
                continue;
            }
            boolean hasN = false, hasS = false;
            for (char c : pol.toCharArray()) {
                if (c == 'N') hasN = true; else hasS = true;
            }
            if (!(hasN && hasS)) out.append(-1).append('\n');
            else if (pol.charAt(0) != pol.charAt(N-1)) out.append(1).append('\n');
            else out.append(2).append('\n');
        }
        System.out.print(out.toString());
    }
}

